class Solution:
    def getCollisionTimes(self, cars):
        n = len(cars)
        ans = [-1.0] * n
        from fractions import Fraction
        for i in range(n - 1):
            pi, si = cars[i]
            best = None
            for j in range(i + 1, n):
                pj, sj = cars[j]
                if sj >= si:
                    continue
                t = Fraction(pj - pi, si - sj)
                if ans[j] != -1 and t > ans[j]:
                    continue
                if best is None or t < best:
                    best = t
            if best is not None:
                ans[i] = best
        return [float(x) if x != -1 else -1.0 for x in ans]

