var getCollisionTimes = function(cars) {
    const n = cars.length;
    const ans = new Array(n).fill(-1);
    const stack = [];
    for (let i = n - 1; i >= 0; i--) {
        const [pi, si] = cars[i];
        while (stack.length) {
            const j = stack[stack.length - 1];
            const [pj, sj] = cars[j];
            if (sj >= si) { stack.pop(); continue; }
            const t = (pj - pi) / (si - sj);
            if (ans[j] > 0 && t > ans[j]) { stack.pop(); continue; }
            ans[i] = t;
            break;
        }
        stack.push(i);
    }
    return ans;
};
